const data = $input.first().json;

// Try to find the words array wherever it is
const words = data.words || data.alignment || data.characters || [];

const transcript = words
  .filter(w => w.type === 'word')
  .map(w => w.text)
  .join(' ');

return [{ json: { transcript } }];

const data = $input.first().json;

// Log everything to find where the date is hiding
const allKeys = JSON.stringify(data, null, 2);

let requested_date = null;
let requested_time = null;

// Check every possible location the AI Agent might put its response
const raw = 
  data.output ||           // most common in n8n AI Agent
  data.text ||             
  data.response ||         
  data.message ||          
  data.content ||          
  data.answer ||           
  (data.generations && data.generations[0]?.[0]?.text) ||
  '';

try {
  const jsonMatch = raw.match(/\{[\s\S]*?\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    requested_date = parsed.requested_date || null;
    requested_time = parsed.requested_time || null;
  }
} catch(e) {}

// Direct fallback
if (!requested_date) requested_date = data.requested_date || null;
if (!requested_time) requested_time = data.requested_time || null;

return [{
  json: {
    ...data,
    requested_date,
    requested_time,
    _debug_raw: raw.substring(0, 500),   // shows what raw text was found
    _debug_all_keys: Object.keys(data)    // shows all available keys
  }
}];

// ============================================================
// BOOKING LOGIC - v5.3
// FIX A: Stale session cleared when new date is mentioned
// FIX B: collecting_details + date (no email) = reset to start
// FIX C: showForm=true on ALL collecting_details transitions
// FIX D: Voice-friendly parseUserDetails (no comma needed)
// FIX E: Month regex uses (?:long|short) non-capturing group
// FIX F: parseSlotChoice won't fire when date like "march 6" contains a digit
// ============================================================

const input = $input.first().json;

let context = {};
try { context = $("session router").first().json; } catch(e) {}

let aiContext = {};
try { aiContext = $("Code in JavaScript1").first().json; } catch(e) {}

const sessionId = (
  context.sessionId ||
  context.body?.sessionId ||
  context.sessionState?.sessionId ||
  'global-session'
).toString();

const userMessage = (
  context.userMessage ||
  context.original_input ||
  context.body?.chatInput ||
  ''
).toString().trim();

const inputSource = context.input_source || 'chat';

// ============================================================
// NPT TIMEZONE HELPERS
// ============================================================
const NPT_OFFSET_MS = (5 * 60 + 45) * 60 * 1000;
const nowUTC = new Date();
const nowNPT = new Date(nowUTC.getTime() + NPT_OFFSET_MS);

const todayNPTStr = [
  nowNPT.getUTCFullYear(),
  String(nowNPT.getUTCMonth() + 1).padStart(2, '0'),
  String(nowNPT.getUTCDate()).padStart(2, '0')
].join('-');

const makeNPT = (dateStr, hour, minute = 0) =>
  new Date(`${dateStr}T${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}:00+05:45`);

const formatSlot = (d) =>
  d.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", timeZone: "Asia/Kathmandu" }) +
  " at " +
  d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit", timeZone: "Asia/Kathmandu" });

const toNPTISO = (d) => {
  if (!d || isNaN(d.getTime())) return null;
  const npt = new Date(d.getTime() + NPT_OFFSET_MS);
  return npt.toISOString().replace('Z', '+05:45');
};

const getNPTHour = (d) => new Date(d.getTime() + NPT_OFFSET_MS).getUTCHours();
const getNPTDay  = (d) => new Date(d.getTime() + NPT_OFFSET_MS).getUTCDay();

const addDays = (dateStr, n) => {
  const d = new Date(dateStr + 'T00:00:00Z');
  d.setUTCDate(d.getUTCDate() + n);
  return d.toISOString().split('T')[0];
};

// FIX E: Month regex with (?:long|short) non-capturing group


// ============================================================
// VOICE TIME PARSER - extracts time from spoken/written message
// MUST run before parseDateFromMessage so date doesn't absorb time digits
// ============================================================
const parseTimeFromMessage = (msg) => {
  if (!msg) return null;
  const lower = msg.toLowerCase();

  const wordToNum = {
    'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
    'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10,
    'eleven': 11, 'twelve': 12
  };

  const ampmRe = /\b(\d{1,2}|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)(?::\d{2})?\s*(a\.?m\.?|p\.?m\.?)\b/i;
  const m = lower.match(ampmRe);
  if (m) {
    let hour = parseInt(m[1]);
    if (isNaN(hour)) hour = wordToNum[m[1].toLowerCase()] || null;
    if (!hour || hour > 12) return null;
    const isPM = /^p/i.test(m[2]);
    if (isPM && hour !== 12) hour += 12;
    else if (!isPM && hour === 12) hour = 0;
    return String(hour).padStart(2, '0') + ':00';
  }

  // HH:MM 24h format
  const h24 = lower.match(/\b([01]?\d|2[0-3]):(\d{2})\b/);
  if (h24) return h24[1].padStart(2,'0') + ':' + h24[2];

  return null;
};

// Returns a cleaned message with time expression blanked out (for safe date parsing)
const stripTimeFromMessage = (msg) => {
  if (!msg) return msg;
  return msg.replace(/\b(?:\d{1,2}|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)(?::\d{2})?\s*(?:a\.?m\.?|p\.?m\.?)\b/gi, ' ');
};

const parseDateFromMessage = (msg) => {
  if (!msg) return null;
  // Strip time expressions first so "march 2 1pm" gives day=2, not day=21
  const cleanMsg = stripTimeFromMessage(msg);
  const lower = cleanMsg.toLowerCase();

  if (/tomorrow/.test(lower)) return addDays(todayNPTStr, 1);
  if (/\btoday\b/.test(lower)) return todayNPTStr;

  const weekdays = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  for (let i = 0; i < weekdays.length; i++) {
    if (lower.includes(weekdays[i])) {
      const diff = ((i - nowNPT.getUTCDay()) + 7) % 7 || 7;
      return addDays(todayNPTStr, diff);
    }
  }

  const months = ['january','february','march','april','may','june','july','august','september','october','november','december'];
  const monthsShort = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];

  for (let i = 0; i < months.length; i++) {
    const pattern = '(?:' + months[i] + '|' + monthsShort[i] + ')';
    const re1 = new RegExp(pattern + '\\s+(\\d{1,2})\\b', 'i');
    const re2 = new RegExp('\\b(\\d{1,2})\\s+' + pattern, 'i');
    let m = lower.match(re1) || lower.match(re2);
    if (m) {
      const day = parseInt(m[1]);
      if (day < 1 || day > 31) continue;
      const year = nowNPT.getUTCFullYear();
      const month = String(i + 1).padStart(2, '0');
      const dayStr = String(day).padStart(2, '0');
      const candidate = `${year}-${month}-${dayStr}`;
      const testDate = new Date(candidate + 'T12:00:00+05:45');
      if (!isNaN(testDate.getTime())) return candidate;
    }
  }

  const isoMatch = msg.match(/(\d{4}-\d{2}-\d{2})/);
  if (isoMatch) return isoMatch[1];

  return null;
};


// ============================================================
// STATIC DATA CLEANUP
// ============================================================
try {
  const sd = $getWorkflowStaticData('global');
  Object.keys(sd).forEach(key => {
    if (!key.startsWith('session_')) return;
    const s = sd[key];
    if (s && s.lastSlots && Array.isArray(s.lastSlots)) {
      if (s.lastSlots.some(slot => typeof slot === 'string' && slot.endsWith('Z'))) delete sd[key];
    }
  });
} catch(e) {}

// ============================================================
// SESSION RESOLUTION
// ============================================================
let session = null;

try {
  const sd = $getWorkflowStaticData('global');
  const saved = sd['session_' + sessionId];
  if (saved && typeof saved === 'object' && saved.step) session = saved;
} catch(e) {}

if (!session) {
  const raw = context.sessionState;
  if (raw && typeof raw === 'object' && raw.step) {
    const hasUTCSlots = raw.lastSlots && raw.lastSlots.some(s => typeof s === 'string' && s.endsWith('Z'));
    if (!hasUTCSlots) session = raw;
  } else if (raw && typeof raw === 'string') {
    try { const p = JSON.parse(raw); if (p && p.step) session = p; } catch(e) {}
  }
}

if (!session) {
  const raw = context.existingSession;
  if (raw && typeof raw === 'object' && raw.step) {
    const sanitized = { ...raw };
    if (sanitized.lastSlots && sanitized.lastSlots.some(s => typeof s === 'string' && s.endsWith('Z'))) {
      sanitized.lastSlots = null;
    }
    session = sanitized;
  }
}

if (!session) session = { step: 'start', sessionId };
if (!session.sessionId) session.sessionId = sessionId;

if (session.step === 'booked') {
  session = { step: 'start', sessionId };
  try { const sd = $getWorkflowStaticData('global'); delete sd['session_' + sessionId]; } catch(e) {}
}

// Date/Time from AI Agent
const reqDate = aiContext.requested_date || context.requested_date || null;
const reqTime = aiContext.requested_time || context.requested_time || parseTimeFromMessage(userMessage) || null;
const parsedDateFromMsg = parseDateFromMessage(userMessage);

// ── Calendar Busy Slots ─────────────────────────────────────
let busySlots = [];
try {
  busySlots = $input.all()
    .filter(e => e.json && (e.json.start || e.json.busy))
    .map(e => {
      const startStr = e.json.start?.dateTime || null;
      const endStr   = e.json.end?.dateTime   || null;
      if (!startStr || !endStr) return null;
      const start = new Date(startStr);
      const end   = new Date(endStr);
      return { start, end };
    })
    .filter(e => e !== null && !isNaN(e.start) && !isNaN(e.end))
    .filter(e => (e.end - e.start) > 0 && (e.end - e.start) <= 24 * 60 * 60 * 1000);
} catch(e) {}

try {
  const sd = $getWorkflowStaticData('global');
  Object.keys(sd).forEach(key => {
    if (!key.startsWith('session_') && !key.startsWith('booked_')) return;
    const s = sd[key];
    if (s && s.startTime && s.endTime) {
      const start = new Date(s.startTime);
      const end   = new Date(s.endTime);
      if (!isNaN(start) && !isNaN(end)) busySlots.push({ start, end });
    }
  });
} catch(e) {}

const nowPlus10   = new Date(nowUTC.getTime() + 10 * 60 * 1000);
const sevenDaysMS = 7 * 24 * 60 * 60 * 1000;
const maxDate     = new Date(nowUTC.getTime() + sevenDaysMS);

const isSlotFree = (start, end) => {
  if (start <= nowPlus10) return false;
  if (start > maxDate) return false;
  const day  = getNPTDay(start);
  const hour = getNPTHour(start);
  if (day === 0 || day === 6) return false;
  if (hour < 10 || hour >= 17) return false;
  return !busySlots.some(b => b.start < end && b.end > start);
};

const getSlots = (dateStrNPT, count = 3, oneDayOnly = false) => {
  let res = [];
  let currDate = dateStrNPT || todayNPTStr;
  let currHour = (currDate === todayNPTStr) ? nowNPT.getUTCHours() + 1 : 10;
  let daysVisited = new Set();
  let safety = 0;

  while (res.length < count && safety < 300) {
    safety++;
    if (currHour >= 17) {
      if (oneDayOnly) break;
      currDate = addDays(currDate, 1);
      currHour = 10;
      continue;
    }
    if (currHour < 10) { currHour = 10; continue; }

    const slotStart = makeNPT(currDate, currHour);
    const slotEnd   = new Date(slotStart.getTime() + 3600000);
    const day = getNPTDay(slotStart);

    if (day === 0 || day === 6) {
      if (oneDayOnly) break;
      currDate = addDays(currDate, 1);
      currHour = 10;
      continue;
    }
    if (slotStart > maxDate) break;

    if (isSlotFree(slotStart, slotEnd)) {
      if (!oneDayOnly) {
        if (!daysVisited.has(currDate)) {
          res.push(slotStart);
          daysVisited.add(currDate);
          currDate = addDays(currDate, 1);
          currHour = 10;
          continue;
        }
      } else {
        res.push(slotStart);
      }
    }
    currHour++;
  }
  return res;
};

// FIX F: Only run slot picker if message is JUST a number (no date words)
const parseSlotChoice = (msg, isoSlots) => {
  // Don't match if message contains a month name or weekday (it's a date, not a slot pick)
  const lower = msg.toLowerCase();
  const dateWords = ['january','february','march','april','may','june','july','august',
                     'september','october','november','december','jan','feb','mar','apr',
                     'jun','jul','aug','sep','oct','nov','dec',
                     'monday','tuesday','wednesday','thursday','friday','saturday','sunday',
                     'today','tomorrow'];
  if (dateWords.some(w => lower.includes(w))) return null;

  const m = msg.match(/\b([1-9])\b/);
  if (m) {
    const idx = parseInt(m[1]) - 1;
    if (idx >= 0 && idx < isoSlots.length) return new Date(isoSlots[idx]);
  }
  return null;
};

// FIX D: Voice-friendly detail parser — works without commas
const parseUserDetails = (msg) => {
  const emailMatch = msg.match(/[\w.+\-]+@[\w\-]+\.[a-zA-Z]{2,}/);
  const email = emailMatch ? emailMatch[0].toLowerCase() : null;
  const withoutEmail = msg.replace(emailMatch ? emailMatch[0] : '', ' ').replace(/\s+/g, ' ').trim();

  // Try comma/pipe/newline split first
  const parts = withoutEmail.split(/[,|\n]+/).map(s => s.trim()).filter(Boolean);

  let name = null, purpose = null;

  if (parts.length >= 2) {
    name = parts[0];
    purpose = parts.slice(1).join(', ');
  } else if (parts.length === 1) {
    // No commas — split by filler words that typically introduce purpose
    // e.g. "John Doe and I want to discuss AI" or "John Doe I just want to have a meeting"
    const purposeMatch = withoutEmail.match(/^([A-Za-z]+(?:\s+[A-Za-z]+)?)\s+(?:and\s+)?(?:i\s+)?(?:want|need|would|just|to|for|about|discuss|regarding|re:)\s+(.+)$/i);
    if (purposeMatch) {
      name = purposeMatch[1].trim();
      purpose = purposeMatch[2].trim();
    } else {
      // Fallback: first 2 words = name, rest = purpose
      const words = parts[0].split(/\s+/);
      if (words.length >= 3) {
        name = words.slice(0, 2).join(' ');
        purpose = words.slice(2).join(' ');
      } else {
        name = parts[0];
      }
    }
  }

  return { name, email, purpose };
};

const saveSession = (s) => {
  try {
    const sd = $getWorkflowStaticData('global');
    if (s.step === 'booked') {
      if (s.startTime && s.endTime) {
        sd['booked_' + s.startTime] = { startTime: s.startTime, endTime: s.endTime };
      }
      delete sd['session_' + sessionId];
    } else {
      sd['session_' + sessionId] = s;
    }
  } catch(e) {}
};

// ============================================================
// STEP MACHINE
// ============================================================

// CANCEL GUARD: If user cancelled, always reset and return clean state
// Catches: 'cancel', '__CANCEL__', "don't want", "not now", "for now", "skip", etc.
const CANCEL_PATTERNS = [
  /^__CANCEL__$/,
  /\bcancel\b/i,
  /don\'?t want to book/i,
  /not want to book/i,
  /don\'?t want/i,
  /\b(stop|quit|exit|nevermind|never mind|no thanks|go back|not now|for now|skip|abort)\b/i,
  /not (right now|now|today|at the moment)/i,
  /no[,.]?\s*(thanks|thank you)/i
];
const isCancelMessage = CANCEL_PATTERNS.some(p => p.test(userMessage));
if (isCancelMessage) {
  const cancelSession = { step: 'start', sessionId, showForm: false };
  try { const sd = $getWorkflowStaticData('global'); delete sd['session_' + sessionId]; } catch(e) {}
  return [{ json: { ...context, session: cancelSession, sessionState: cancelSession,
    replyMessage: 'No problem at all! Your booking has been cancelled. Is there anything else I can help you with?',
    readyToBook: false, showForm: false, booking_start: null, booking_end: null,
    input_source: inputSource } }];
}

let reply = "";
let next  = { ...session };
let ready = false;

// ── STEP: start ─────────────────────────────────────────────
if (session.step === 'start') {

  if (session.lastSlots && session.lastSlots.length > 0) {
    const choice = parseSlotChoice(userMessage, session.lastSlots);
    if (choice) {
      const slotEnd = new Date(choice.getTime() + 3600000);
      const slot    = formatSlot(choice);
      next = { ...next, step: 'collecting_details', selectedSlot: slot,
               startTime: toNPTISO(choice), endTime: toNPTISO(slotEnd), lastSlots: null, showForm: true };
      reply = `Great choice! ${slot} is confirmed. To finalize your booking, please share your full name, email address, and the purpose of your meeting.`;
      saveSession(next);
      return [{ json: { ...context, session: next, sessionState: next, replyMessage: reply,
                        readyToBook: false, showForm: true, booking_start: next.startTime,
                        booking_end: next.endTime, input_source: inputSource,
                        id_debug: "ID: " + sessionId + " | step: " + next.step } }];
    }
  }

  const effectiveDate = reqDate || parsedDateFromMsg;

  if (effectiveDate && reqTime) {
    const [reqHour, reqMin] = reqTime.split(':').map(Number);
    const slotStart = makeNPT(effectiveDate, reqHour, reqMin || 0);
    const slotEnd   = new Date(slotStart.getTime() + 3600000);

    if (isNaN(slotStart.getTime())) {
      const sug = getSlots(null, 3);
      next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      reply = `I couldn't understand that date. Here are available slots this week:\n` +
        sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") + `\n\nReply with 1, 2, or 3 to pick.`;

    } else if (slotStart <= nowPlus10) {
      const sug = getSlots(effectiveDate, 5, true);
      next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      reply = `That time has already passed. Available slots for that day:\n` +
        (sug.length ? sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") : "No slots available that day.") +
        (sug.length ? `\n\nReply with a number to pick.` : '');

    } else if (reqHour < 10 || reqHour >= 17) {
      const sug = getSlots(effectiveDate, 5, true);
      next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      reply = `Our office hours are 10 AM to 5 PM NPT. Available slots for that day:\n` +
        sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") + `\n\nReply with a number to pick.`;

    } else if (isSlotFree(slotStart, slotEnd)) {
      const slot = formatSlot(slotStart);
      next = { ...next, step: 'collecting_details', selectedSlot: slot,
               startTime: toNPTISO(slotStart), endTime: toNPTISO(slotEnd), lastSlots: null, showForm: true };
      reply = `${slot} is available! To finalize your booking, please share your full name, email address, and the purpose of your meeting. For example: John Doe, john@email.com, Discuss AI integration`;

    } else {
      const sug = getSlots(effectiveDate, 5, true);
      next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      reply = `That slot is already taken. Available slots for that day:\n` +
        (sug.length ? sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") : "No slots available that day. Try another date!") +
        (sug.length ? `\n\nReply with a number to pick.` : '');
    }

  } else if (effectiveDate) {
    const testDate = new Date(effectiveDate + 'T12:00:00+05:45');
    if (isNaN(testDate.getTime())) {
      const sug = getSlots(null, 5);
      next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      reply = `I couldn't find that date. Here are available slots this week:\n` +
        sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") +
        `\n\nReply with a number to pick, or tell me a specific date.`;
    } else {
      const sug = getSlots(effectiveDate, 7, true);
      next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      const dateLabel = testDate.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", timeZone: "Asia/Kathmandu" });
      if (sug.length === 0) {
        const altSug = getSlots(null, 3);
        next = { ...next, lastSlots: altSug.map(s => toNPTISO(s)) };
        reply = `No available slots on that day. Here are the next available slots:\n` +
          altSug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") +
          `\n\nReply with 1, 2, or 3 to pick, or tell me another date.`;
      } else {
        reply = `Available slots for ${dateLabel}:\n` +
          sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") +
          `\n\nReply with a number to pick, or tell me a different date.`;
      }
    }

  } else {
    const sug = getSlots(null, 5);
    next = { ...next, lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
    if (sug.length === 0) {
      reply = `No available slots in the next 7 days. Please contact us directly!`;
    } else {
      reply = `I would love to help you book a meeting! Here are available slots this week:\n` +
        sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") +
        `\n\nReply with a number to pick, or tell me a specific date like "Wednesday" or "March 5".`;
    }
  }

// ── STEP: collecting_details ────────────────────────────────
} else if (session.step === 'collecting_details') {

  const { name, email, purpose } = parseUserDetails(userMessage);
  const missing = [];
  if (!name)    missing.push("your full name");
  if (!email)   missing.push("your email address");
  if (!purpose) missing.push("the purpose of your meeting");

  if (missing.length > 0) {
    reply = `I still need ${missing.join(", ")}. Please send them in one message.\n` +
      `For example: John Doe, john@email.com, Discuss AI integration\n\n` +
      `(Say "cancel" anytime to stop.)`;
    next = { ...next, step: 'collecting_details', showForm: true };
  } else {
    let slotAlreadyBooked = false;
    if (next.startTime && next.endTime) {
      try {
        const sd = $getWorkflowStaticData('global');
        Object.keys(sd).forEach(key => {
          if (!key.startsWith('booked_')) return;
          const b = sd[key];
          if (b && b.startTime && b.endTime) {
            const bStart = new Date(b.startTime), bEnd = new Date(b.endTime);
            const myStart = new Date(next.startTime), myEnd = new Date(next.endTime);
            if (bStart < myEnd && bEnd > myStart) slotAlreadyBooked = true;
          }
        });
      } catch(e) {}
    }

    if (slotAlreadyBooked) {
      const sug = getSlots(null, 3);
      next = { ...session, step: 'start', lastSlots: sug.map(s => toNPTISO(s)), showForm: false };
      reply = `Oh no! That slot was just booked by someone else. Here are the next available slots:\n` +
        sug.map((s, i) => `${i+1}. ${formatSlot(s)}`).join("\n") +
        `\n\nReply with 1, 2, or 3 to pick a new slot.`;
      saveSession(next);
      return [{ json: { ...context, session: next, sessionState: next, replyMessage: reply,
                        readyToBook: false, showForm: false, booking_start: null, booking_end: null,
                        input_source: inputSource, id_debug: "ID: " + sessionId + " | step: start | slot_stolen" } }];
    }

    next  = { ...next, step: 'booked', name, email, purpose, showForm: false };
    ready = true;
    reply = `Booking confirmed! Your meeting is set for ${next.selectedSlot}. Name: ${name}. Email: ${email}. Purpose: ${purpose}. A calendar invite and confirmation email will be sent to ${email}. See you soon!`;
  }

} else {
  next  = { step: 'start', sessionId, showForm: false };
  reply = `Something went wrong. Let's start fresh. Just say "I want to book" to begin.`;
}

saveSession(next);

return [{
  json: {
    ...context,
    session:      next,
    sessionState: next,
    replyMessage: reply,
    readyToBook:  ready,
    showForm: next.showForm || false,
    booking_start: next.startTime || null,
    booking_end:   next.endTime   || null,
    input_source: inputSource,
    id_debug: "ID: " + sessionId + " | step: " + next.step
  }
}];

