parameters.jsCode:
const findSessionId = (input) => {
  return (
    input.sessionId ||
    input.body?.sessionId ||
    input.sessionState?.sessionId ||
    input.body?.sessionState?.sessionId ||
    'session-' + Date.now() + '-' + Math.random().toString(36).substr(2,9)
  ).toString();
};

const findUserMessage = (input) => {
  return (
    input.userMessage ||
    input.body?.chatInput ||
    input.body?.message ||
    input.body?.text ||
    input.text ||
    input.original_input ||
    ''
  ).toString().trim();
};

const parseSession = (raw) => {
  if (!raw) return null;
  if (typeof raw === 'object' && raw.step) return raw;
  try {
    if (typeof raw === 'string') {
      const parsed = JSON.parse(raw);
      if (parsed && parsed.step) return parsed;
    }
  } catch(e) {}
  return null;
};

const mentionsNewDate = (msg) => {
  if (!msg) return false;
  const lower = msg.toLowerCase();
  const months = ['january','february','march','april','may','june','july','august',
                  'september','october','november','december','jan','feb','mar','apr',
                  'may','jun','jul','aug','sep','oct','nov','dec'];
  if (months.some(m => lower.includes(m))) return true;
  if (/\btomorrow\b/.test(lower)) return true;
  if (/\btoday\b/.test(lower)) return true;
  const weekdays = ['monday','tuesday','wednesday','thursday','friday','saturday','sunday'];
  if (weekdays.some(d => lower.includes(d))) return true;
  if (/\b\d{1,2}(:\d{2})?\s*(am|pm)\b/i.test(msg)) return true;
  return false;
};

const input = $input.first().json;
const sessionId = findSessionId(input);
const userMessage = findUserMessage(input);

const emailMatch = userMessage.match(/[\w.+\-]+@[\w\-]+\.[a-zA-Z]{2,}/);
const hasEmail = !!emailMatch;

// ── Parse incoming sessionState ──────────────────────────────────────────────
let session = parseSession(input.sessionState) ||
              parseSession(input.body?.sessionState) ||
              parseSession(input.existingSession) ||
              { step: 'start', sessionId };

if (!session.sessionId) session.sessionId = sessionId;

// ── STATELESS mid-lookup detection (uses sessionState.pendingAction) ─────────
// This works even if static data is cleared or sessionId changes
const pendingAction = session.pendingAction || null;

// Also check explicit step values (more reliable than pendingAction alone)
const explicitStep = session.step || '';

// Direct step-based routing - most reliable
if (explicitStep === 'reschedule_awaiting_date' && session.pendingChosenEventId) {
  // User is providing new date/time for reschedule
  return [{
    json: {
      ...input,
      sessionId,
      userMessage,
      knownName: session.knownName || null,
      existingSession: null,
      sessionState: { ...session, sessionId },
      text: 'reschedule_meeting',
      _meetingAction: 'reschedule_meeting',
      _midReschedule: true,
      _hasPendingEvents: true,
      _midLookup: false,
      _rescheduleSession: {
        chosenEventId: session.pendingChosenEventId,
        chosenEventSummary: session.pendingChosenEventSummary,
        chosenEventStart: session.pendingChosenEventStart,
        chosenEventEnd: session.pendingChosenEventEnd,
        chosenEventEmail: session.pendingEmail,
        email: session.pendingEmail,
        step: 'awaiting_new_slot'
      },
      _matchFound: true,
      _matchedEvents: [],
      _lookupEmail: session.pendingEmail,
      id_debug: 'ID: ' + sessionId + ' | reschedule_awaiting_date step'
    }
  }];
}

if (explicitStep === 'reschedule_pick_event' && session.pendingEmail) {
  // User is picking which meeting to reschedule (from a list)
  const storedEvents = session.pendingMatchedEvents || [];
  return [{
    json: {
      ...input,
      sessionId,
      userMessage,
      knownName: session.knownName || null,
      existingSession: null,
      sessionState: { ...session, sessionId },
      text: 'reschedule_meeting',
      _meetingAction: 'reschedule_meeting',
      _hasPendingEvents: storedEvents.length > 0,
      _midLookup: false,
      _midReschedule: false,
      _forceRescheduleStep1: true,
      _matchFound: storedEvents.length > 0,
      _matchedEvents: storedEvents,
      _lookupEmail: session.pendingEmail,
      id_debug: 'ID: ' + sessionId + ' | reschedule_pick_event step'
    }
  }];
}

if (explicitStep === 'cancel_awaiting_confirm' && session.pendingEmail) {
  // User is confirming cancel or picking from list
  const storedEvents = session.pendingMatchedEvents || [];
  return [{
    json: {
      ...input,
      sessionId,
      userMessage,
      knownName: session.knownName || null,
      existingSession: null,
      sessionState: { ...session, sessionId },
      text: 'cancel_meeting',
      _meetingAction: 'cancel_meeting',
      _hasPendingEvents: storedEvents.length > 0,
      _midLookup: storedEvents.length > 0,
      _matchFound: storedEvents.length > 0,
      _matchedEvents: storedEvents,
      _lookupEmail: session.pendingEmail,
      _forceCancelStep: true,
      id_debug: 'ID: ' + sessionId + ' | cancel_awaiting_confirm step'
    }
  }];
}

if (explicitStep === 'lookup_awaiting_email' && hasEmail) {
  // User is providing email after being asked
  const action = pendingAction || 'cancel_meeting';
  // Clear any stale static lookup session
  try { const sd2 = $getWorkflowStaticData('global'); delete sd2['lookup_' + sessionId]; } catch(e) {}
  return [{
    json: {
      ...input,
      sessionId,
      userMessage,
      knownName: session.knownName || null,
      existingSession: null,
      sessionState: { ...session, sessionId },
      text: action,
      _meetingAction: action,
      _midLookup: true,
      _hasPendingEvents: false,
      id_debug: 'ID: ' + sessionId + ' | lookup_awaiting_email step'
    }
  }];
}

if (pendingAction && (pendingAction === 'cancel_meeting' || pendingAction === 'reschedule_meeting')) {
  // We're in a pending action flow

  // Case A: waiting for email and user provides one
  if (!session.pendingEmail && hasEmail) {
    return [{
      json: {
        ...input,
        sessionId,
        userMessage,
        knownName: session.knownName || null,
        existingSession: null,
        sessionState: { ...session, sessionId },
        text: pendingAction,
        _meetingAction: pendingAction,
        _midLookup: true,
        id_debug: 'ID: ' + sessionId + ' | mid-lookup via sessionState: ' + pendingAction
      }
    }];
  }

  // Case B: email already collected (pendingEmail set), now waiting for new date (reschedule)
  if (pendingAction === 'reschedule_meeting' && session.pendingEmail && session.pendingChosenEventId && mentionsNewDate(userMessage)) {
    return [{
      json: {
        ...input,
        sessionId,
        userMessage,
        knownName: session.knownName || null,
        existingSession: null,
        sessionState: { ...session, sessionId },
        text: 'reschedule_meeting',
        _meetingAction: 'reschedule_meeting',
        _midLookup: false,
        _midReschedule: true,
        _hasPendingEvents: true,
        _rescheduleSession: {
          chosenEventId: session.pendingChosenEventId,
          chosenEventSummary: session.pendingChosenEventSummary,
          chosenEventStart: session.pendingChosenEventStart,
          chosenEventEnd: session.pendingChosenEventEnd,
          chosenEventEmail: session.pendingEmail,
          email: session.pendingEmail,
          step: 'awaiting_new_slot'
        },
        _matchFound: true,
        _matchedEvents: [],
        _lookupEmail: session.pendingEmail,
        id_debug: 'ID: ' + sessionId + ' | mid-reschedule via sessionState'
      }
    }];
  }

  // Case C: email collected + events stored -> user is confirming/picking (yes/no/1/2/3)
  if (session.pendingEmail && session.pendingMatchedEvents && session.pendingMatchedEvents.length > 0) {
    const storedEvents = session.pendingMatchedEvents;
    return [{
      json: {
        ...input,
        sessionId,
        userMessage,
        knownName: session.knownName || null,
        existingSession: null,
        sessionState: { ...session, sessionId },
        text: pendingAction,
        _meetingAction: pendingAction,
        _matchFound: true,
        _matchedEvents: storedEvents,
        _lookupEmail: session.pendingEmail,
        _hasPendingEvents: true,
        _midLookup: true,
        id_debug: 'ID: ' + sessionId + ' | confirm/pick: ' + pendingAction
      }
    }];
  }

  // Case C2: email collected, no events stored yet (shouldn't happen but safety)
  if (session.pendingEmail && !session.pendingChosenEventId && !session.pendingMatchedEvents) {
    return [{
      json: {
        ...input,
        sessionId,
        userMessage,
        knownName: session.knownName || null,
        existingSession: null,
        sessionState: { ...session, sessionId },
        text: pendingAction,
        _meetingAction: pendingAction,
        _midLookup: true,
        _hasPendingEvents: false,
        id_debug: 'ID: ' + sessionId + ' | re-lookup: ' + pendingAction
      }
    }];
  }
}

// ── Also check static data as backup ────────────────────────────────────────
let sd;
try { sd = $getWorkflowStaticData('global'); } catch(e) { sd = {}; }

const lookupKey = 'lookup_' + sessionId;
const lookupSession = sd[lookupKey];

if (lookupSession && lookupSession.step === 'awaiting_email' && hasEmail) {
  const action = lookupSession.action || 'cancel_meeting';
  return [{
    json: {
      ...input,
      sessionId,
      userMessage,
      knownName: null,
      existingSession: null,
      sessionState: { step: 'start', sessionId },
      text: action,
      _meetingAction: action,
      _midLookup: true,
      id_debug: 'ID: ' + sessionId + ' | mid-lookup via staticData: ' + action
    }
  }];
}

const rescheduleKey = 'reschedule_' + sessionId;
const rescheduleSession = sd[rescheduleKey];

if (rescheduleSession && rescheduleSession.step === 'awaiting_new_slot' && mentionsNewDate(userMessage)) {
  return [{
    json: {
      ...input,
      sessionId,
      userMessage,
      knownName: null,
      existingSession: null,
      sessionState: { step: 'start', sessionId },
      text: 'reschedule_meeting',
      _meetingAction: 'reschedule_meeting',
      _midReschedule: true,
      _rescheduleSession: rescheduleSession,
      _matchFound: true,
      _matchedEvents: [],
      _lookupEmail: rescheduleSession.email,
      id_debug: 'ID: ' + sessionId + ' | mid-reschedule via staticData'
    }
  }];
}

// ── Normal session routing ──────────────────────────────────────────────────
if (session.step === 'booked') {
  session = { step: 'start', sessionId };
  try { delete sd['session_' + sessionId]; } catch(e) {}
}

let knownName = session.knownName || null;
if (!knownName) {
  const namePatterns = [
    /(?:i'?m|i am|my name is|this is|call me|it'?s)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)?)/i,
    /^([A-Z][a-z]+(?:\s+[A-Z][a-z]+)?)\s*,\s*[\w.+\-]+@/i
  ];
  for (const pat of namePatterns) {
    const m = userMessage.match(pat);
    if (m && m[1] && m[1].length > 1) { knownName = m[1].trim(); break; }
  }
}
if (!knownName && session.knownName) knownName = session.knownName;

const safeSessionId = sessionId && sessionId !== 'undefined' && sessionId !== 'null'
  ? sessionId : 'session-' + Date.now();

return [{
  json: {
    ...input,
    sessionId: safeSessionId,
    userMessage,
    knownName: knownName || null,
    existingSession: null,
    sessionState: { ...session, sessionId: safeSessionId, knownName: knownName || null },
    id_debug: 'ID: ' + safeSessionId + ' | step: ' + session.step
  }
}];

