parameters.jsCode:
const input = $input.first().json;
const sessionId = (
  input.sessionId ||
  input.body?.sessionId ||
  input.sessionState?.sessionId ||
  'global-session'
).toString();

const intent = (input.text || '').toLowerCase().trim();

// Always preserve userMessage
const userMessage = (
  input.userMessage ||
  input.original_input ||
  input.body?.chatInput ||
  ''
).toString().trim();

// Check if we are in collecting_details step
const currentStep = input.sessionState?.step || input.existingSession?.step || 'start';
const hasEmail = /[\w.+\-]+@[\w\-]+\.[a-zA-Z]{2,}/.test(userMessage);

// CRITICAL FIX: If user is providing details (email present) in collecting_details step,
// NEVER treat this as a cancel — pass through intact for booking_logic routing
if (currentStep === 'collecting_details' && hasEmail) {
  return [{
    json: {
      ...input,
      userMessage,
      original_input: userMessage,
      _cancelCheckBypassed: true
    }
  }];
}

const isCancel = intent.includes('cancel') || 
                 /\b(stop|quit|exit|nevermind|never mind|don\'t want|dont want|no thanks|go back|not now|for now|not interested|i don\'t|i dont|don\'t book|dont book|skip|no booking|abort)\b/i.test(userMessage) ||
                 /don\'?t want to book/i.test(userMessage) ||
                 /not (right now|now|today|at the moment)/i.test(userMessage) ||
                 /i(\'m| am) (fine|good|ok|okay)/i.test(userMessage) ||
                 /no[,.]? (thanks|thank you|i\'?m good)/i.test(userMessage);

if (isCancel) {
  try {
    const sd = $getWorkflowStaticData('global');
    delete sd['session_' + sessionId];
  } catch(e) {}

  return [{
    json: {
      ...input,
      userMessage: '__CANCEL__',
      original_input: '__CANCEL__',
      sessionState: { 
        step: 'start', 
        sessionId,
        selectedSlot: null,
        startTime: null,
        endTime: null,
        lastSlots: null,
        showForm: false,
        pendingAction: null,
        pendingEmail: null,
        pendingMatchedEvents: null,
        pendingChosenEventId: null
      },
      existingSession: null,
      _wasCancelled: true,
      id_debug: (input.id_debug || '') + ' | CANCELLED'
    }
  }];
}

// Normal — pass through with userMessage intact
return [{
  json: {
    ...input,
    userMessage,
    original_input: userMessage
  }
}];

// Collect email for meeting lookup (reschedule or cancel_meeting)
const input = $input.first().json;
const sessionId = (
  input.sessionId ||
  input.sessionState?.sessionId ||
  'session-' + Date.now()
).toString();
const userMessage = (input.userMessage || input.original_input || input.body?.chatInput || '').trim();

// Determine intentAction from all sources
const classifierText = (input.text || '').toLowerCase().trim();
const meetingAction = (input._meetingAction || '').toLowerCase().trim();

let intentAction;
if (meetingAction.includes('reschedule') || classifierText.includes('reschedule')) {
  intentAction = 'reschedule_meeting';
} else {
  intentAction = 'cancel_meeting';
}

// Also check static data backup
let sd;
try { sd = $getWorkflowStaticData('global'); } catch(e) { sd = {}; }
const lookupKey = 'lookup_' + sessionId;
let lookupSession = sd[lookupKey] || {};
if (lookupSession.action) {
  intentAction = lookupSession.action.includes('reschedule') ? 'reschedule_meeting' : 'cancel_meeting';
}

// Check for email in message
const emailMatch = userMessage.match(/[\w.+\-]+@[\w\-]+\.[a-zA-Z]{2,}/);
const email = emailMatch ? emailMatch[0].toLowerCase() : null;

if (!email) {
  // No email - ask for it
  // Save in BOTH static data AND will embed in sessionState via reply
  lookupSession.step = 'awaiting_email';
  lookupSession.action = intentAction;
  try { sd[lookupKey] = lookupSession; } catch(e) {}

  const actionVerb = intentAction === 'reschedule_meeting' ? 'reschedule' : 'cancel';
  const msgs = [
    `To ${actionVerb} your meeting, I need to locate your booking. What email address did you use when you booked?`,
    `Sure! I just need the email you registered with to pull up your meeting. Could you share that?`,
    `No problem — what email address was used when booking the meeting?`
  ];
  const msg = msgs[Math.floor(Date.now() / 1000) % msgs.length];

  // KEY: embed pendingAction in sessionState so frontend returns it on next message
  const currentSession = input.sessionState || { step: 'start', sessionId };
  const pendingSessionState = {
    ...(typeof currentSession === 'string' ? JSON.parse(currentSession) : currentSession),
    sessionId,
    pendingAction: intentAction
  };

  return [{
    json: {
      ...input,
      sessionId,
      _lookupStep: 'awaiting_email',
      _meetingAction: intentAction,
      _pendingSessionState: pendingSessionState,
      replyMessage: msg,
      readyToLookup: false
    }
  }];
}

// Email provided - proceed
try { delete sd[lookupKey]; } catch(e) {}

// Clear pendingAction since we now have email
const currentSession = input.sessionState || { step: 'start', sessionId };
const resolvedSession = typeof currentSession === 'string' ? JSON.parse(currentSession) : currentSession;

return [{
  json: {
    ...input,
    sessionId,
    _lookupEmail: email,
    _meetingAction: intentAction,
    _lookupStep: 'has_email',
    _resolvedSessionState: { ...resolvedSession, sessionId, pendingAction: intentAction, pendingEmail: email },
    readyToLookup: true
  }
}];

// Match Google Calendar events to the user's email
const allItems = $input.all();
const lookupNode = $('Lookup Meeting by Email').first().json;
const lookupEmail = lookupNode._lookupEmail || '';
const intentAction = lookupNode._meetingAction || 'cancel_meeting';
const sessionInput = $('session router').first().json;

if (!lookupEmail) {
  return [{
    json: {
      ...sessionInput,
      _meetingAction: intentAction,
      replyMessage: "I couldn't locate the email address. Please tell me the email you used when booking.",
      _matchFound: false
    }
  }];
}

// Filter events where this email appears as attendee, in description, or in summary
const matched = allItems
  .map(i => i.json)
  .filter(ev => {
    if (!ev || !ev.start) return false;
    const attendees = (ev.attendees || []);
    const emailLower = lookupEmail.toLowerCase();
    const inAttendees = attendees.some(a => (a.email || '').toLowerCase() === emailLower);
    const inDesc = (ev.description || '').toLowerCase().includes(emailLower);
    const inSummary = (ev.summary || '').toLowerCase().includes(emailLower);
    return inAttendees || inDesc || inSummary;
  })
  .sort((a, b) => new Date(a.start?.dateTime || a.start?.date) - new Date(b.start?.dateTime || b.start?.date));

if (matched.length === 0) {
  return [{
    json: {
      ...sessionInput,
      _meetingAction: intentAction,
      _lookupEmail: lookupEmail,
      _matchFound: false,
      replyMessage: `I searched but couldn't find any upcoming meetings linked to **${lookupEmail}**. Please double-check the email — it must match exactly what was used when booking. Or say "I want to book" to schedule a new meeting.`
    }
  }];
}

const formatDT = (dtStr) => {
  if (!dtStr) return 'Unknown time';
  return new Date(dtStr).toLocaleString('en-US', {
    weekday: 'long', month: 'long', day: 'numeric',
    hour: 'numeric', minute: '2-digit', timeZone: 'Asia/Kathmandu'
  });
};

const isCancel = intentAction === 'cancel_meeting';
const actionVerb = isCancel ? 'cancel' : 'reschedule';
const actionEmoji = isCancel ? '❌' : '🔄';

// Build numbered meeting list (max 3)
const displayList = matched.slice(0, 3);
const meetingLines = displayList.map((ev, i) => {
  const dt = formatDT(ev.start?.dateTime || ev.start?.date);
  return `**${i + 1}.** ${ev.summary || 'Meeting'} — 📅 ${dt}`;
}).join('\n');

let replyMessage;
if (displayList.length === 1) {
  replyMessage = `${actionEmoji} Found **1 meeting** for **${lookupEmail}**:\n\n${meetingLines}\n\nWould you like to ${actionVerb} this meeting? Reply **yes** to confirm, or **no** to keep it.`;
} else {
  replyMessage = `${actionEmoji} Found **${displayList.length} upcoming meetings** for **${lookupEmail}**:\n\n${meetingLines}\n\nWhich one would you like to ${actionVerb}? Reply with **1**, **2**, or **3**.`;
}

// Build sessionState with pendingEmail so next turn knows we have email
const lookupNodeOutput = $('Lookup Meeting by Email').first().json;
const existingSession = sessionInput.sessionState || { step: 'start' };
const matchSessionState = {
  ...(typeof existingSession === 'object' ? existingSession : {}),
  sessionId: sessionInput.sessionId,
  pendingAction: intentAction,
  pendingEmail: lookupEmail,
  pendingMatchedEvents: displayList.map(ev => ({
    id: ev.id,
    summary: ev.summary,
    start: ev.start,
    end: ev.end,
    attendees: (ev.attendees || [])
  }))
};

return [{
  json: {
    ...sessionInput,
    _meetingAction: intentAction,
    _lookupEmail: lookupEmail,
    _matchFound: true,
    _matchSessionState: matchSessionState,
    _matchedEvents: displayList.map(ev => ({
      id: ev.id,
      summary: ev.summary,
      start: ev.start?.dateTime || ev.start?.date,
      end: ev.end?.dateTime || ev.end?.date,
      attendees: (ev.attendees || []).map(a => a.email)
    })),
    replyMessage
  }
}];

// Process Cancel Meeting - production grade
const input = $input.first().json;
const rawMsg = (input.userMessage || input.original_input || '').trim();
const userMessage = rawMsg.toLowerCase();
const events = input._matchedEvents || [];
const lookupEmail = input._lookupEmail || input.sessionState?.pendingEmail || '';

if (!input._matchFound || events.length === 0) {
  return [{ json: {
    ...input,
    replyMessage: input.replyMessage || "I couldn't find your meeting details. Could you say 'cancel my meeting' to start again?",
    _readyToDelete: false
  }}];
}

const formatDT = (dtStr) => {
  if (!dtStr) return 'unknown time';
  try {
    return new Date(dtStr).toLocaleString('en-US', {
      weekday: 'long', month: 'long', day: 'numeric',
      hour: 'numeric', minute: '2-digit', timeZone: 'Asia/Kathmandu'
    });
  } catch(e) { return dtStr; }
};

// SECURITY: verify lookupEmail
if (!lookupEmail) {
  return [{ json: {
    ...input,
    replyMessage: "I couldn't verify your identity. Please start again by saying 'cancel my meeting'.",
    _readyToDelete: false
  }}];
}

let chosenEvent = null;

if (events.length === 1) {
  // Single event - accept yes/ok/confirm/1 or any non-negative
  const isNo = /\b(no|nope|keep|don't|dont|nevermind|never mind|stop|cancel it|back)\b/i.test(userMessage);
  if (isNo) {
    return [{ json: {
      ...input,
      replyMessage: "No problem — your meeting has been kept as is. Is there anything else I can help you with?",
      _readyToDelete: false,
      _cancelAborted: true
    }}];
  }
  // Accept yes, 1, ok, confirm, sure, go ahead, or anything that isn't a clear no
  chosenEvent = events[0];
} else {
  // Multiple events - must pick a number
  const numMatch = userMessage.match(/\b([1-9])\b/);
  if (numMatch) {
    const idx = parseInt(numMatch[1]) - 1;
    if (idx >= 0 && idx < events.length) chosenEvent = events[idx];
  }
  if (!chosenEvent && /\bfirst\b/i.test(userMessage)) chosenEvent = events[0];
  else if (!chosenEvent && /\bsecond\b/i.test(userMessage)) chosenEvent = events[1];
  else if (!chosenEvent && /\bthird\b/i.test(userMessage)) chosenEvent = events[2];

  if (!chosenEvent) {
    // Build the list again for re-prompting
    const list = events.slice(0,3).map((ev,i) =>
      `**${i+1}.** ${ev.summary || 'Meeting'} — ${formatDT(ev.start)}`
    ).join('\n');
    return [{ json: {
      ...input,
      _matchedEvents: events,
      replyMessage: `Please reply with **1**, **2**, or **3** to select which meeting to cancel:\n\n${list}`,
      _readyToDelete: false
    }}];
  }
}

if (!chosenEvent || !chosenEvent.id) {
  return [{ json: {
    ...input,
    replyMessage: "I couldn't identify that meeting. Please say 'cancel my meeting' to try again.",
    _readyToDelete: false
  }}];
}

// All good - ready to delete
return [{ json: {
  ...input,
  _chosenEventId: chosenEvent.id,
  _chosenEventSummary: chosenEvent.summary,
  _chosenEventStart: chosenEvent.start,
  _chosenEventEnd: chosenEvent.end,
  _chosenEventEmail: lookupEmail,
  _readyToDelete: true,
  replyMessage: `Processing the cancellation of "${chosenEvent.summary}" on ${formatDT(chosenEvent.start)}...`
}}];

