parameters.jsCode:
// Process Reschedule - production grade
const input = $input.first().json;
const rawMsg = (input.userMessage || input.original_input || '').trim();
const userMessage = rawMsg.toLowerCase();
const sessionId = (input.sessionId || input.sessionState?.sessionId || 'session-' + Date.now()).toString();
const ss = (typeof input.sessionState === 'object' ? input.sessionState : {}) || {};

let sd;
try { sd = $getWorkflowStaticData('global'); } catch(e) { sd = {}; }
const rKey = 'reschedule_' + sessionId;

// Build rSession from all available sources
let rSession = sd[rKey] || {};
if (input._rescheduleSession?.chosenEventId) {
  rSession = { ...rSession, ...input._rescheduleSession };
}
if (!rSession.chosenEventId && ss.pendingChosenEventId) {
  rSession = {
    chosenEventId: ss.pendingChosenEventId,
    chosenEventSummary: ss.pendingChosenEventSummary || 'Meeting',
    chosenEventStart: ss.pendingChosenEventStart || '',
    chosenEventEnd: ss.pendingChosenEventEnd || '',
    chosenEventEmail: ss.pendingEmail || '',
    email: ss.pendingEmail || '',
    step: 'awaiting_new_slot',
    sessionId
  };
}

// If forced to step 1 (user picking from list), clear any stale rSession
if (input._forceRescheduleStep1) {
  try { delete sd[rKey]; } catch(e) {}
  rSession = {};
}

const events = input._matchedEvents || [];
const lookupEmail = input._lookupEmail || rSession.email || ss.pendingEmail || '';

const formatDT = (dtStr) => {
  if (!dtStr) return 'unknown time';
  try {
    return new Date(dtStr).toLocaleString('en-US', {
      weekday: 'long', month: 'long', day: 'numeric',
      hour: 'numeric', minute: '2-digit', timeZone: 'Asia/Kathmandu'
    });
  } catch(e) { return dtStr; }
};

const baseMatchSession = {
  ...ss,
  sessionId,
  pendingAction: 'reschedule_meeting',
  pendingEmail: lookupEmail
};

if (!input._matchFound && !rSession.chosenEventId) {
  return [{ json: {
    ...input,
    replyMessage: input.replyMessage || "I couldn't find your meeting. Please say 'reschedule my meeting' to try again.",
    _readyToReschedule: false,
    _matchSessionState: baseMatchSession
  }}];
}

// ── STEP 1: Pick which event ──────────────────────────────────────
if (!rSession.chosenEventId) {
  const secureEvents = events.filter(ev => ev && ev.id);
  if (!secureEvents.length) {
    return [{ json: {
      ...input,
      replyMessage: "No meetings found to reschedule.",
      _readyToReschedule: false,
      _matchSessionState: baseMatchSession
    }}];
  }

  let chosenEvent = null;
  if (secureEvents.length === 1) {
    chosenEvent = secureEvents[0];
  } else {
    const numMatch = rawMsg.match(/\b([1-9])\b/);
    if (numMatch) {
      const idx = parseInt(numMatch[1]) - 1;
      if (idx >= 0 && idx < secureEvents.length) chosenEvent = secureEvents[idx];
    }
    if (!chosenEvent && /\bfirst\b/i.test(userMessage)) chosenEvent = secureEvents[0];
    else if (!chosenEvent && /\bsecond\b/i.test(userMessage)) chosenEvent = secureEvents[1];
    else if (!chosenEvent && /\bthird\b/i.test(userMessage)) chosenEvent = secureEvents[2];

    if (!chosenEvent) {
      const list = secureEvents.slice(0,3).map((ev,i) =>
        `**${i+1}.** ${ev.summary || 'Meeting'} — ${formatDT(ev.start)}`
      ).join('\n');
      return [{ json: {
        ...input,
        _matchedEvents: secureEvents,
        _matchSessionState: { ...baseMatchSession, pendingMatchedEvents: secureEvents },
        _rescheduleSubStep: 'pick_event',
        replyMessage: `Which meeting would you like to reschedule?\n\n${list}\n\nReply with **1**, **2**, or **3**.`,
        _readyToReschedule: false
      }}];
    }
  }

  // Save chosen event
  rSession = {
    chosenEventId: chosenEvent.id,
    chosenEventSummary: chosenEvent.summary,
    chosenEventStart: chosenEvent.start,
    chosenEventEnd: chosenEvent.end,
    chosenEventEmail: lookupEmail,
    email: lookupEmail,
    step: 'awaiting_new_slot',
    sessionId
  };
  try { sd[rKey] = rSession; } catch(e) {}

  const pendingState = {
    ...baseMatchSession,
    pendingChosenEventId: chosenEvent.id,
    pendingChosenEventSummary: chosenEvent.summary,
    pendingChosenEventStart: chosenEvent.start,
    pendingChosenEventEnd: chosenEvent.end,
    pendingMatchedEvents: []
  };

  const prompts = [
    `🔄 Got it — rescheduling **"${chosenEvent.summary}"** (currently ${formatDT(chosenEvent.start)}).\n\nWhat new date and time would you like? For example: *"Monday March 10 at 2 PM"*`,
    `Sure! I'll move **"${chosenEvent.summary}"** from ${formatDT(chosenEvent.start)}.\n\nWhat new date and time works for you?`,
    `Let's reschedule **"${chosenEvent.summary}"**.\n\nWhen would you like to move it to?`
  ];

  return [{ json: {
    ...input,
    sessionId,
    _rescheduleSession: rSession,
    _matchSessionState: pendingState,
    _readyToReschedule: false,
    _rescheduleSubStep: 'awaiting_date',
    replyMessage: prompts[Math.floor(Date.now() / 1000) % prompts.length]
  }}];
}

// ── STEP 2: Parse the new date/time ──────────────────────────────
if (rSession.step === 'awaiting_new_slot') {
  const now = new Date();
  const yr = now.getFullYear();

  const months = {january:1,february:2,march:3,april:4,may:5,june:6,july:7,august:8,
    september:9,october:10,november:11,december:12,
    jan:1,feb:2,mar:3,apr:4,jun:6,jul:7,aug:8,sep:9,oct:10,nov:11,dec:12};
  const days = {monday:1,tuesday:2,wednesday:3,thursday:4,friday:5,saturday:6,sunday:0};

  let targetDate = null;
  let hour = null, minute = 0;
  const lc = userMessage;

  if (/\btomorrow\b/.test(lc)) {
    targetDate = new Date(now); targetDate.setDate(now.getDate()+1);
  } else if (/\btoday\b/.test(lc)) {
    targetDate = new Date(now);
  } else {
    for (const [d,n] of Object.entries(days)) {
      if (lc.includes(d)) {
        let ahead = n - now.getDay(); if (ahead<=0) ahead+=7;
        targetDate = new Date(now); targetDate.setDate(now.getDate()+ahead); break;
      }
    }
    if (!targetDate) {
      for (const [m,n] of Object.entries(months)) {
        const rx = new RegExp('\\b'+m+'\\s+(\\d{1,2})');
        const match = rx.exec(lc);
        if (match) {
          targetDate = new Date(yr, n-1, parseInt(match[1]));
          if (targetDate < now) targetDate.setFullYear(yr+1);
          break;
        }
      }
    }
    if (!targetDate) {
      for (const [m,n] of Object.entries(months)) {
        const rx = new RegExp('(\\d{1,2})\\s+'+m);
        const match = rx.exec(lc);
        if (match) {
          targetDate = new Date(yr, n-1, parseInt(match[1]));
          if (targetDate < now) targetDate.setFullYear(yr+1);
          break;
        }
      }
    }
    if (!targetDate) {
      const dm = lc.match(/(\d{1,2})[\/-](\d{1,2})(?:[\/-](\d{2,4}))?/);
      if (dm) {
        const a=parseInt(dm[1]),b=parseInt(dm[2]),y=dm[3]?parseInt(dm[3]):yr;
        targetDate = new Date(y<100?2000+y:y, a-1, b);
        if (targetDate<now && !dm[3]) targetDate.setFullYear(yr+1);
      }
    }
  }

  const tm = rawMsg.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm)/i);
  if (tm) {
    hour = parseInt(tm[1]); minute = tm[2]?parseInt(tm[2]):0;
    if (tm[3].toLowerCase()==='pm' && hour<12) hour+=12;
    if (tm[3].toLowerCase()==='am' && hour===12) hour=0;
  } else {
    const t24 = rawMsg.match(/\b(\d{1,2}):(\d{2})\b/);
    if (t24) { hour=parseInt(t24[1]); minute=parseInt(t24[2]); }
  }

  if (!targetDate || hour===null) {
    try { sd[rKey] = rSession; } catch(e) {}
    const pendingState = {
      ...ss, sessionId, pendingAction:'reschedule_meeting',
      pendingEmail: rSession.email,
      pendingChosenEventId: rSession.chosenEventId,
      pendingChosenEventSummary: rSession.chosenEventSummary,
      pendingChosenEventStart: rSession.chosenEventStart,
      pendingChosenEventEnd: rSession.chosenEventEnd,
      pendingMatchedEvents: []
    };
    return [{ json: {
      ...input, sessionId,
      _rescheduleSession: rSession,
      _matchSessionState: pendingState,
      _readyToReschedule: false,
      replyMessage: `I didn't catch that. Could you say the date and time again? For example: *"Wednesday March 5 at 3 PM"* or *"tomorrow at 10 AM"*.`
    }}];
  }

  // ── TIMEZONE FIX: Treat hour/minute as Nepal local time (UTC+5:45) ──
  const NPT_OFFSET_MS = (5 * 60 + 45) * 60 * 1000; // 5h45m in milliseconds

  // Use UTC date components from targetDate to avoid server timezone interference
  const newStartMs = Date.UTC(
    targetDate.getFullYear(),
    targetDate.getMonth(),
    targetDate.getDate(),
    hour,
    minute,
    0,
    0
  ) - NPT_OFFSET_MS;

  // Calculate duration from original event (preserve meeting length)
  let durationMs = 60 * 60 * 1000; // default 1hr
  if (rSession.chosenEventStart && rSession.chosenEventEnd) {
    const d = new Date(rSession.chosenEventEnd) - new Date(rSession.chosenEventStart);
    if (d > 0) durationMs = d;
  }

  const newStart = new Date(newStartMs).toISOString();
  const newEnd = new Date(newStartMs + durationMs).toISOString();

  try { delete sd[rKey]; } catch(e) {}

  return [{ json: {
    ...input,
    sessionId,
    _chosenEventId: rSession.chosenEventId,
    _chosenEventSummary: rSession.chosenEventSummary,
    _chosenEventEmail: rSession.chosenEventEmail || lookupEmail,
    _oldStart: rSession.chosenEventStart,
    _newStart: newStart,
    _newEnd: newEnd,
    _newStartFormatted: formatDT(newStart),
    _readyToReschedule: true,
    _meetingAction: 'reschedule_meeting',
    replyMessage: `Rescheduling your meeting to ${formatDT(newStart)}...`
  }}];
}

return [{ json: {
  ...input,
  replyMessage: "Something went wrong. Please say 'reschedule my meeting' to start over.",
  _readyToReschedule: false
}}];

