// Language Detection - English Only
const input = $input.first().json;
const text = (
  input.original_input ||
  input.userMessage ||
  input.body?.chatInput ||
  input.text ||
  ''
).trim();

// If empty or very short, pass through (could be a command)
if (!text || text.length < 3) {
  return [{ json: { ...input, _languageOk: true } }];
}

// English character detection
// English text is dominated by ASCII letters
const asciiLetters = (text.match(/[a-zA-Z]/g) || []).length;
const totalChars = text.replace(/\s/g, '').length;
const asciiRatio = totalChars > 0 ? asciiLetters / totalChars : 1;

// Detect obvious non-Latin scripts (Chinese, Arabic, Devanagari, Cyrillic, etc.)
const hasNonLatin = /[\u0080-\u024F\u0370-\u03FF\u0400-\u04FF\u0600-\u06FF\u0900-\u097F\u4E00-\u9FFF\u3040-\u309F\u30A0-\u30FF\uAC00-\uD7AF]/u.test(text);

// If non-latin script detected OR very low ASCII ratio for multi-char text
const isNonEnglish = hasNonLatin || (totalChars > 5 && asciiRatio < 0.6);

if (isNonEnglish) {
  return [{
    json: {
      ...input,
      _languageOk: false,
      _languageReply: "I'm sorry, I can only process messages in English. Please write your message in English and I'll be happy to help you! 😊"
    }
  }];
}

return [{ json: { ...input, _languageOk: true } }];

